#!/usr/bin/env node
// patch-s30c2-korpus-en.mjs — Sprint 30 · C2: Englischer Begleitungs-Korpus.
//
// Führt prompts.en.js ein, registriert ihn in der Sprachweiche, fügt die
// Sprachdisziplin-Zeile in alle sechs de-Systemprompts ein („Begleitung, nicht
// Leitung" in momentSys) und parametrisiert alle App-gebauten Kontext-/
// Ergebnistexte über K().korpusTexte (kernwetten/sessions/prozess/app + i18n).
//
// Basis: origin/main mit s30c1 (Commit 15edeeb, Kern 70f2517d5fdafb5a).
// Ergebnis: Kern 5e43aa3691ae44e7, 326 Tests grün.
//
// Aufruf:  node patch-s30c2-korpus-en.mjs [--dry-run]   (im Repo-Wurzelverzeichnis)
//
// Verhalten je Hunk: Ziel-Text schon vorhanden → skip (idempotent);
// Anker genau einmal vorhanden → ersetzen; sonst → Report, KEIN Überschreiben.
// Neue Dateien: identisch vorhanden → skip; abweichend vorhanden → Report.

import { readFileSync, writeFileSync, existsSync, mkdirSync } from "node:fs";
import { dirname } from "node:path";

const DRY = process.argv.includes("--dry-run");
const b64 = s => Buffer.from(s, "base64").toString("utf8");

/* ── Guards: C1 muss vorhanden sein ── */
function guard() {
  const fail = msg => { console.error("ABBRUCH: " + msg + " — zuerst patch-s30c1 anwenden (Basis: Commit 15edeeb)."); process.exit(1); };
  if (!existsSync("core/prompts/prompts.js")) fail("core/prompts/prompts.js fehlt");
  const pj = readFileSync("core/prompts/prompts.js", "utf8");
  if (!pj.includes("setKorpusSprache")) fail("Sprachweiche (setKorpusSprache) fehlt in prompts.js");
  const pde = readFileSync("core/prompts/prompts.de.js", "utf8");
  if (!pde.includes("korpusTexte")) fail("korpusTexte fehlt in prompts.de.js");
}

