const NEW_FILES = {
"core/prompts/prompts.en.js": "",
"tests/unit/korpus-sprache.spec.js": "",
"docs/SPRINT-30C2-PROTOKOLL.md": ""
};

guard();
let ok = 0, skip = 0, fail = 0;

for (const [rel, hunks] of Object.entries(EDITS)) {
  if (!existsSync(rel)) { console.error("FEHLT: " + rel); fail++; continue; }
  let s = readFileSync(rel, "utf8");
  let touched = false, broken = false;
  hunks.forEach((h, i) => {
    const alt = b64(h.old), neu = b64(h.new);
    if (s.includes(neu)) { skip++; return; }                       // schon angewendet
    const n = s.split(alt).length - 1;
    if (n === 1) { s = s.replace(alt, neu); touched = true; ok++; }
    else { console.error(`ANKER-MISMATCH ${rel} · Hunk ${i + 1}: ${n}× gefunden (erwartet 1×)`); broken = true; fail++; }
  });
  if (broken) { console.error("  → " + rel + " NICHT geschrieben."); continue; }
  if (touched && !DRY) writeFileSync(rel, s);
  console.log((touched ? (DRY ? "würde ändern:  " : "geändert:      ") : "unverändert:   ") + rel);
}

for (const [rel, data] of Object.entries(NEW_FILES)) {
  const inhalt = b64(data);
  if (existsSync(rel)) {
    if (readFileSync(rel, "utf8") === inhalt) { console.log("vorhanden:     " + rel); skip++; continue; }
    console.error("KONFLIKT: " + rel + " existiert mit abweichendem Inhalt — NICHT überschrieben."); fail++; continue;
  }
  if (!DRY) { mkdirSync(dirname(rel), { recursive: true }); writeFileSync(rel, inhalt); }
  console.log((DRY ? "würde anlegen: " : "angelegt:      ") + rel);
  ok++;
}

console.log(`\nS30·C2 ${DRY ? "(dry-run) " : ""}— ok: ${ok} · skip: ${skip} · fail: ${fail}`);
if (fail) { console.error("Mindestens ein Schritt schlug fehl — Repo-Stand prüfen."); process.exit(1); }
console.log("Danach: npm install && npx vitest run  (erwartet: 326 grün) · npm run build (Kern 5e43aa3691ae44e7)");
